from flask import Flask, request, Response
from prometheus_client import Counter, Histogram, generate_latest
import time
import hashlib

app = Flask(__name__)

# --- Prometheus Metrics ---

# Counter for total API requests
# Labels:
# - method: HTTP method (e.g., GET, POST)
# - endpoint: The URL path of the request (e.g., /api/data)
# - status: HTTP status code of the response (e.g., 200, 400, 500)
# - user_id: Identifier for the user making the request (extracted from X-User-ID header)
# - api_key: API key used for the request (extracted from X-API-Key header)
# - body_hash: SHA256 hash of the request body.
#              WARNING: Using body_hash as a label can lead to extremely high cardinality
#              if request bodies vary frequently and uniquely. This can overwhelm
#              Prometheus. For production systems with diverse bodies, consider
#              using a boolean 'body_present' label, categorizing body types/sizes,
#              or omitting body content from metrics altogether.
API_REQUESTS_TOTAL = Counter(
    'api_requests_total',
    'Total number of API requests.',
    ['method', 'endpoint', 'status', 'user_id', 'api_key', 'body_hash']
)

# Histogram for API request duration
# Labels are the same as API_REQUESTS_TOTAL.
API_REQUEST_DURATION_SECONDS = Histogram(
    'api_request_duration_seconds',
    'Histogram of API request duration in seconds.',
    ['method', 'endpoint', 'status', 'user_id', 'api_key', 'body_hash']
)

# --- Helper function to extract request labels ---
def get_request_labels(req, resp=None):
    """
    Extracts relevant labels from a Flask request and response object.
    """
    method = req.method
    endpoint = req.path
    status = resp.status_code if resp else 'unknown' # Status might not be available before response
    user_id = req.headers.get('X-User-ID', 'anonymous') # Default to 'anonymous' if header is missing
    api_key = req.headers.get('X-API-Key', 'none')      # Default to 'none' if header is missing

    # Handle request body for metrics
    body_content = req.get_data() # Get raw request body
    if body_content:
        # Generate SHA256 hash of the body content
        body_hash = hashlib.sha256(body_content).hexdigest()
    else:
        body_hash = 'no_body' # Consistent label for requests without a body

    return {
        'method': method,
        'endpoint': endpoint,
        'status': str(status), # Convert status code to string for labels
        'user_id': user_id,
        'api_key': api_key,
        'body_hash': body_hash
    }

# --- Flask Hooks for Metrics Collection ---

@app.before_request
def before_request_hook():
    """
    Records the start time of each request.
    """
    request.start_time = time.time()

@app.after_request
def after_request_hook(response):
    """
    Collects and records metrics after each request has been processed.
    """
    duration = time.time() - request.start_time
    labels = get_request_labels(request, response)

    # Increment the total request counter
    API_REQUESTS_TOTAL.labels(**labels).inc()

    # Observe the request duration
    API_REQUEST_DURATION_SECONDS.labels(**labels).observe(duration)

    return response

# --- Application Endpoints ---

@app.route('/')
def hello_world():
    """A simple greeting endpoint."""
    return "Hello, World! This is an API endpoint."

@app.route('/api/data', methods=['GET', 'POST'])
def api_data():
    """
    An API endpoint for fetching or submitting data.
    - GET: Returns a generic message.
    - POST: Expects JSON data in the request body.
            Simulates processing and returns the received data.
    """
    if request.method == 'POST':
        try:
            data = request.get_json()
            if data:
                # Simulate some processing time
                time.sleep(0.05)
                return {"message": "Data received successfully", "your_data": data}, 200
            else:
                return {"error": "No JSON data provided or invalid JSON"}, 400
        except Exception as e:
            return {"error": f"Failed to parse JSON: {e}"}, 400
    return {"message": "This is GET data endpoint"}, 200

@app.route('/api/user/<user_id>', methods=['GET'])
def get_user(user_id):
    """
    An API endpoint to retrieve user information by ID.
    Simulates a small delay for processing.
    """
    # Simulate some processing time
    time.sleep(0.1)
    return {"user_id": user_id, "name": f"User {user_id}", "status": "active"}, 200

@app.route('/api/error')
def simulate_error():
    """
    An API endpoint that always returns an internal server error (500)
    to demonstrate error metric collection.
    """
    return {"error": "Something went wrong on the server"}, 500

# --- Prometheus Metrics Endpoint ---

@app.route('/metrics')
def metrics():
    """
    Exposes Prometheus metrics at the /metrics endpoint.
    This endpoint is designed to be scraped by a Prometheus server.
    """
    return Response(generate_latest(), mimetype='text/plain')

# --- Main execution ---
if __name__ == '__main__':
    # Run the Flask application
    # host='0.0.0.0' makes the server accessible from other machines on the network
    # debug=True enables debug mode, which includes a reloader and debugger
    app.run(host='0.0.0.0', port=5000, debug=True)

